import { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useNavigate } from 'react-router-dom';
import Plot from 'react-plotly.js';

// Mock Questions Database
const questions = [
  { id: 1, text: "A car accelerates uniformly from rest. Which graph correctly shows velocity-time?", options: ["Linear increasing", "Parabolic", "Constant horizontal", "Exponential"], correct: 0, topic: "Mechanics" },
  { id: 2, text: "According to Le Chatelier's principle, increasing pressure on N2 + 3H2 ⇌ 2NH3 favors:", options: ["Forward reaction", "Backward reaction", "No effect", "Depends on temp"], correct: 0, topic: "Physical Chemistry" },
  { id: 3, text: "The first law of thermodynamics is essentially the law of conservation of:", options: ["Momentum", "Energy", "Mass", "Charge"], correct: 1, topic: "Thermodynamics" },
  { id: 4, text: "Which molecule exhibits sp3d hybridization?", options: ["CH4", "SF6", "PCl5", "BF3"], correct: 2, topic: "Inorganic Chemistry" },
  { id: 5, text: "Two point charges +q and -q are distance r apart. How does force change if distance is doubled?", options: ["Halves", "Doubles", "Reduces to 1/4", "Increases 4x"], correct: 2, topic: "Electrostatics" },
];

export default function DiagnosticQuiz() {
  const navigate = useNavigate();
  const [currentIdx, setCurrentIdx] = useState(0);
  const [answers, setAnswers] = useState<number[]>([]);
  const [timeLeft, setTimeLeft] = useState(30);
  const [isFinished, setIsFinished] = useState(false);
  const warningsRef = useRef(0);
  const videoRef = useRef<HTMLVideoElement>(null);

  // Attempt to grab webcam stream
  useEffect(() => {
    let stream: MediaStream | null = null;
    if (navigator.mediaDevices && navigator.mediaDevices.getUserMedia) {
      navigator.mediaDevices.getUserMedia({ video: true })
        .then(s => {
          stream = s;
          if (videoRef.current) videoRef.current.srcObject = s;
        })
        .catch(err => console.warn("Camera access denied or missing.", err));
    }
    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  // Timer Countdown
  useEffect(() => {
    if (isFinished) return;
    if (timeLeft <= 0) {
      handleNext(-1); // Automatically submit empty answer if time runs out
      return;
    }
    const timer = setInterval(() => setTimeLeft(t => t - 1), 1000);
    return () => clearInterval(timer);
  }, [timeLeft, isFinished]);

  // Tab switch detection (Proctoring)
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.hidden && !isFinished) {
        warningsRef.current += 1;
        if (warningsRef.current >= 2) {
           alert('Maximum tab switches reached. Auto-submitting quiz.');
           setIsFinished(true);
        } else {
           alert('Warning: Please do not switch tabs during the quiz.');
        }
        console.log(`Proctoring warning ${warningsRef.current} recorded.`);
      }
    };

    document.addEventListener("visibilitychange", handleVisibilityChange);
    return () => document.removeEventListener("visibilitychange", handleVisibilityChange);
  }, [isFinished]);

  const handleNext = (optIdx: number) => {
    const newAnswers = [...answers, optIdx];
    setAnswers(newAnswers);
    if (currentIdx < questions.length - 1) {
      setCurrentIdx(currentIdx + 1);
      setTimeLeft(30);
    } else {
      setIsFinished(true);
    }
  };

  if (isFinished) {
    // Generate random radar data for mockup
    const trace = {
      type: 'scatterpolar',
      r: [85, 90, 60, 70, 80, 85],
      theta: ['Mechanics', 'Thermodynamics', 'Electrostatics', 'Organic Chem', 'Inorganic Chem', 'Physical Chem', 'Mechanics'],
      fill: 'toself',
      fillcolor: 'rgba(0, 212, 255, 0.2)',
      line: { color: '#00d4ff' }
    };

    return (
      <div className="min-h-screen flex items-center justify-center p-8 mt-12">
        <div className="glass-card max-w-4xl w-full p-12 text-center relative overflow-hidden">
           <div className="absolute top-0 right-0 w-64 h-64 bg-brand-violet/20 blur-[100px] pointer-events-none rounded-full"></div>
           <h2 className="text-4xl font-heading font-bold mb-4 text-white">Diagnostic Analysis Complete</h2>
           <p className="text-gray-400 mb-8 max-w-2xl mx-auto">Our ML Recommender Engine has gathered enough features vector data to personalize your lab experience.</p>

           <div className="flex justify-center mb-8 bg-[#050d1a]/50 p-6 rounded-2xl border border-white/5">
             <Plot
               data={[{ ...trace, type: 'scatterpolar' as any }]}
               layout={{
                 polar: {
                   radialaxis: { visible: true, range: [0, 100], color: 'rgba(255,255,255,0.3)', gridcolor: 'rgba(255,255,255,0.1)' },
                   angularaxis: { color: 'rgba(255,255,255,0.8)', gridcolor: 'rgba(255,255,255,0.1)' },
                   bgcolor: 'rgba(0,0,0,0)'
                 },
                 showlegend: false,
                 paper_bgcolor: 'rgba(0,0,0,0)',
                 plot_bgcolor: 'rgba(0,0,0,0)',
                 font: { color: '#f0f9ff' },
                 margin: { t: 30, b: 30, l: 30, r: 30 },
                 height: 400,
                 width: 500
               }}
               config={{ displayModeBar: false }}
             />
           </div>

           <button onClick={() => navigate('/dashboard')} className="px-8 py-4 bg-brand-cyan hover:bg-brand-cyan/80 text-[#050d1a] font-bold rounded-full neon-glow transition-all">
             View My Recommendations
           </button>
        </div>
      </div>
    );
  }

  const q = questions[currentIdx];

  return (
    <div className="min-h-screen pt-24 px-6 relative">
       {/* Live Camera Proctoring Feed */}
       <div className="absolute top-24 right-6 w-48 h-32 bg-black/50 border border-brand-cyan/30 rounded-lg overflow-hidden glass-card z-50">
          <video ref={videoRef} autoPlay playsInline muted className="object-cover w-full h-full transform scale-x-[-1]" />
          <div className="absolute top-2 left-2 flex items-center gap-1.5">
             <div className="w-2 h-2 rounded-full bg-red-500 animate-pulse"></div>
             <span className="text-[10px] uppercase font-bold text-red-500 tracking-wider">Live</span>
          </div>
       </div>

       <div className="max-w-3xl mx-auto mt-12">
          <div className="flex justify-between items-end mb-6">
             <div>
                <span className="text-brand-cyan font-bold tracking-wider uppercase text-sm mb-1 block">Question {currentIdx + 1} of {questions.length}</span>
                <span className="text-gray-400 text-sm">Topic: {q.topic}</span>
             </div>
             <div className="text-right">
                <div className="text-3xl font-heading font-bold font-mono" style={{ color: timeLeft <= 10 ? '#ef4444' : '#f0f9ff' }}>00:{timeLeft.toString().padStart(2, '0')}</div>
             </div>
          </div>

          <div className="w-full bg-black/40 h-1.5 rounded-full mb-12 overflow-hidden border border-white/5">
             <div className="bg-gradient-to-r from-brand-violet to-brand-cyan h-full transition-all duration-300" style={{ width: `${((currentIdx + 1) / questions.length) * 100}%` }}></div>
          </div>

          <AnimatePresence mode="wait">
             <motion.div key={currentIdx} initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -20 }} transition={{ duration: 0.3 }}>
                <h3 className="text-2xl font-bold font-heading mb-8 leading-relaxed text-white">
                  {q.text}
                </h3>

                <div className="space-y-4">
                   {q.options.map((opt, i) => (
                     <button
                       key={i}
                       onClick={() => handleNext(i)}
                       className="w-full text-left p-6 glass-card border-white/10 hover:border-brand-cyan/50 hover:bg-white/5 transition-all outline-none focus:border-brand-cyan group"
                     >
                        <span className="inline-block w-8 font-mono text-gray-500 group-hover:text-brand-cyan transition-colors">{String.fromCharCode(65 + i)}.</span>
                        <span className="text-lg text-gray-200">{opt}</span>
                     </button>
                   ))}
                </div>
             </motion.div>
          </AnimatePresence>
       </div>
    </div>
  );
}

