  const [varState, setVarState] = useState<Record<string, number>>({});
  const [points, setPoints] = useState<{x: number, y: number}[]>([]);

  useEffect(() => {
    // 1. Validate routing param against known mock data
    const exp = experiments.find(e => e.id === experimentId);
    if (!exp) {
       navigate('/labs'); // fallback
       return;
    }
    setExperiment(exp);

    // 2. Initialize default variables
    const initialVars: Record<string, number> = {};
    exp.variables.forEach(v => {
      initialVars[v.id] = v.defaultValue;
    });
    setVarState(initialVars);

    // 3. Reset data points on new lab load
    setPoints([]);
