             </div>

             {/* Tab Content Area */}
             <div className="flex-1 overflow-y-auto p-6 scrollbar-thin scrollbar-thumb-white/10">
                <AnimatePresence mode="wait">
                   <motion.div
                     key={activeTab}
                     initial={{ opacity: 0, x: 20 }}
                     animate={{ opacity: 1, x: 0 }}
                     exit={{ opacity: 0, x: -20 }}
                     transition={{ duration: 0.2 }}
                     className="h-full"
                   >
                      {activeTab === 'instructions' && (
                        <div className="space-y-6">
                           <h2 className="text-2xl font-heading font-bold text-text-primary mb-2 border-b border-border-subtle pb-4">{experiment.title}</h2>

                           <div>
                             <h3 className="text-sm font-bold text-accent-cyan uppercase tracking-wider mb-2">Objective</h3>
                             <p className="text-sm text-text-secondary leading-relaxed p-4 bg-bg-surface border border-border-subtle rounded">
                                {experiment.description}
                             </p>
                           </div>

                           <div>
                             <h3 className="text-sm font-bold text-accent-cyan uppercase tracking-wider mb-2">Procedure</h3>
                             <ul className="space-y-3">
                               {experiment.procedure.map((step, idx) => (
                                 <li key={idx} className="flex gap-3 text-sm text-text-secondary items-start">
                                    <span className="shrink-0 w-6 h-6 rounded-full bg-bg-surface border border-border-subtle flex items-center justify-center text-xs font-bold font-mono">{idx + 1}</span>
                                    <span className="pt-1">{step.text}</span>
                                 </li>
                               ))}
                             </ul>
                           </div>
                        </div>
                      )}

                      {activeTab === 'observations' && (
                        <div>
                           <div className="flex justify-between items-center mb-4">
                             <h2 className="text-xl font-heading font-bold text-white">Data Table</h2>
                             <button className="text-xs text-brand-cyan hover:underline">Clear Data</button>
                           </div>
                           <table className="w-full text-left border-collapse text-sm">                                <thead>
                                 <tr className="border-b border-border-subtle bg-bg-surface font-mono text-text-secondary">
                                    <th className="p-3">S.No</th>
                                    <th className="p-3">{experiment.variables[0]?.name || "Var 1"}</th>
                                    <th className="p-3">Observation</th>
                                 </tr>
                               </thead>
                               <tbody>
                                  {points.map((p, i) => (
                                    <tr key={i} className="border-b border-border-subtle hover:bg-bg-surface/50">
                                       <td className="p-3 font-mono text-text-muted">{i + 1}</td>
                                       <td className="p-3 font-bold text-text-primary">{p.x.toFixed(1)}</td>
                                       <td className="p-3 text-accent-cyan font-mono">{p.y.toFixed(4)}</td>
                                    </tr>
                                  ))}
                                 {points.length === 0 && <tr><td colSpan={4} className="p-4 text-center text-gray-500">No data points recorded yet.</td></tr>}
                              </tbody>
                           </table>
                        </div>
                      )}

                      {activeTab === 'graphs' && (
                        <div className="h-full flex flex-col">
                           <h2 className="text-xl font-heading font-bold text-text-primary mb-4">Observation Plot</h2>
                           <div className="flex-1 bg-bg-primary border border-border-subtle rounded overflow-hidden">
                              {points.length > 0 ? (
                                <Plot
                                  data={[
                                    {
                                      x: points.map(p => p.x),
                                      y: points.map(p => p.y),
                                      type: 'scatter',
                                      mode: 'lines+markers',
                                      marker: { color: 'var(--accent-cyan)', size: 8 },
                                      line: { color: 'var(--accent-cyan)', width: 2, shape: 'spline' }
                                    }
                                  ]}
                                  layout={{
                                    autosize: true,
                                    margin: { l: 40, r: 20, t: 20, b: 40 },
                                    paper_bgcolor: 'transparent',
                                    plot_bgcolor: 'transparent',
                                    font: { color: 'var(--text-secondary)' },
                                    xaxis: { title: { text: experiment.variables[0]?.name || 'X' }, showgrid: true, gridcolor: 'var(--border-subtle)', color: 'var(--text-secondary)' },
                                    yaxis: { title: { text: 'Observation' }, showgrid: true, gridcolor: 'var(--border-subtle)', color: 'var(--text-secondary)' },
                                  }}
                                  useResizeHandler={true}
                                  config={{ displayModeBar: false, responsive: true }}
                                  style={{ width: '100%', height: '100%' }}
                                />
                              ) : (
                                <div className="text-text-muted text-sm p-4 text-center mt-20">Record data points to view graph generation in real-time.</div>
                              )}
                           </div>
                        </div>
                      )}
                   </motion.div>
                </AnimatePresence>
             </div>
          </div>

          {/* Floating AI Assistant Chat Bot */}
          <div className="absolute bottom-6 right-6 lg:right-[42%] z-50 flex flex-col items-end">
             <AnimatePresence>
                {chatOpen && (
                  <motion.div 
                    initial={{ opacity: 0, y: 20, scale: 0.95 }}
                    animate={{ opacity: 1, y: 0, scale: 1 }}
                    exit={{ opacity: 0, y: 20, scale: 0.95 }}
                    className="w-80 h-96 mb-4 glass-card border-brand-violet/30 shadow-[0_10px_40px_rgba(0,0,0,0.5)] flex flex-col overflow-hidden"
                  >
                     <div className="bg-brand-violet/20 p-3 border-b border-brand-violet/30 flex justify-between items-center">
                        <div className="flex items-center gap-2">
                          <span className="text-xl">🤖</span>
                          <span className="font-bold text-sm text-white">ARISE Assistant</span>
                        </div>
                        <button onClick={() => setChatOpen(false)} className="text-gray-400 hover:text-white">&times;</button>
                     </div>
                     <div className="flex-1 p-4 overflow-y-auto space-y-4">
                        <div className="bg-white/5 border border-white/10 rounded-lg rounded-tl-none p-3 text-sm text-gray-300">
                           Hello! I notice you're working on the Simple Pendulum lab. Notice how the mass doesn't affect the time period? Ask me why!
                        </div>
                     </div>
                     <div className="p-3 border-t border-white/10 bg-black/40">
                        <input type="text" placeholder="Ask a physics question..." className="w-full bg-white/5 border border-white/10 rounded px-3 py-2 text-sm text-white focus:outline-none focus:border-brand-cyan" />
                     </div>
                  </motion.div>
                )}
             </AnimatePresence>

             <button 
               onClick={() => setChatOpen(!chatOpen)}
               className="w-14 h-14 rounded-full bg-accent-violet text-white shadow-lg shadow-accent-violet/30 flex items-center justify-center hover:scale-105 transition-transform"
             >
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"></path></svg>
             </button>
          </div>

       </div>

       {/* Tailwind keyframes for the simple CSS pendulum animation */}
       <style>{`
         @keyframes swing {
           0% { transform: rotate(15deg); }
           100% { transform: rotate(-15deg); }
         }
       `}</style>
    </div>
  );
}
